import java.util.Vector;

public class VectorExample {
 public static void main(String[] args) {
 Vector<String> vector = new Vector<>();
 vector.add("Element1");
 vector.add("Element2");
 vector.insertElementAt("New Element", 0);
 vector.setSize(10);
 System.out.println(vector);
 }
}

import java.util.Stack;

public class StackExample {
 public static void main(String[] args) {
 Stack<Integer> stack = new Stack<>();
 stack.push(10);
 stack.push(20);
 System.out.println(stack.pop()); // prints 20
 System.out.println(stack.peek()); // prints 10
 }
}

import java.util.Hashtable;

public class HashtableExample {
 public static void main(String[] args) {
 Hashtable<Integer, String> hashtable = new Hashtable<>();
 hashtable.put(1, "Value1");
 hashtable.put(2, "Value2");
 System.out.println(hashtable.get(1)); // prints Value1
 }
}
